#include <torch/library.h>
#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

static inline at::Tensor make_output_like_fire(const at::Tensor& x,
                                               const at::Tensor& w_expand1,
                                               const at::Tensor& w_expand3) {
    // x: [N, C_in, H, W]
    auto sizes = x.sizes();
    TORCH_CHECK(sizes.size() == 4, "x must be 4D NCHW");
    int64_t N = sizes[0], H = sizes[2], W = sizes[3];
    int64_t C_e1 = w_expand1.size(0);
    int64_t C_e3 = w_expand3.size(0);
    std::vector<int64_t> out_sizes = {N, C_e1 + C_e3, H, W};
    return at::empty(out_sizes, x.options());
}

